	"html/template"
	"net/http"
)

var searchPageTmpl = template.Must(template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
	<meta charset="utf-8">
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: {{.Keyword}}</h2>
</body>
</html>`))

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	_ = searchPageTmpl.Execute(w, struct {
		Keyword string
	}{
		Keyword: keyword,
	})
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	_ = http.ListenAndServe(":8080", nil)
}

