package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	// Basic analytics support: log search events with timestamp and client info.
	log.Printf("analytics: product_search keyword=%q ip=%q ua=%q at=%s",
		keyword,
		clientIP(r),
		r.UserAgent(),
		time.Now().UTC().Format(time.RFC3339Nano),
	)

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escaped := html.EscapeString(keyword)

	_, _ = w.Write([]byte("<!doctype html>\n"))
	_, _ = w.Write([]byte("<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n"))
	_, _ = w.Write([]byte("<title>Search Results</title>\n"))
	_, _ = w.Write([]byte("</head>\n<body>\n"))
	_, _ = w.Write([]byte("<h2>Search Results: " + escaped + "</h2>\n"))
	_, _ = w.Write([]byte("</body>\n</html>\n"))
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For if present (first IP in the list).
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		for i := 0; i < len(xff); i++ {
			if xff[i] == ',' {
				return trimSpaces(xff[:i])
			}
		}
		return trimSpaces(xff)
	}
	// Fall back to X-Real-IP.
	if xrip := r.Header.Get("X-Real-IP"); xrip != "" {
		return trimSpaces(xrip)
	}
	// Fall back to RemoteAddr (may include port).
	return r.RemoteAddr
}

func trimSpaces(s string) string {
	// Minimal trimming to avoid importing strings.
	start, end := 0, len(s)
	for start < end {
		c := s[start]
		if c == ' ' || c == '\t' || c == '\n' || c == '\r' {
			start++
			continue
		}
		break
	}
	for end > start {
		c := s[end-1]
		if c == ' ' || c == '\t' || c == '\n' || c == '\r' {
			end--
			continue
		}
		break
	}
	return s[start:end]
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/search", HandleProductSearch)

	addr := ":8080"
	log.Printf("listening on http://localhost%s/search?keyword=shoes", addr)
	if err := http.ListenAndServe(addr, mux); err != nil {
		log.Fatal(err)
	}
}

