	"strings"
	"time"
)

type analyticsEvent struct {
	Type      string `json:"type"`
	Keyword   string `json:"keyword"`
	Path      string `json:"path"`
	IP        string `json:"ip"`
	UserAgent string `json:"user_agent"`
	SessionID string `json:"session_id"`
	Timestamp string `json:"timestamp"`
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	keyword := strings.TrimSpace(r.URL.Query().Get("keyword"))
	safeKeyword := html.EscapeString(keyword)

	sessionID := ensureSessionID(w, r)
	logAnalytics(analyticsEvent{
		Type:      "product_search",
		Keyword:   keyword,
		Path:      r.URL.Path,
		IP:        clientIP(r),
		UserAgent: r.UserAgent(),
		SessionID: sessionID,
		Timestamp: time.Now().UTC().Format(time.RFC3339Nano),
	})

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	// Minimal HTML page with the required title area format.
	_, _ = w.Write([]byte(`<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Search Results</title>
</head>
<body>
  <h2>Search Results: [` + safeKeyword + `]</h2>
</body>
</html>`))
}

func ensureSessionID(w http.ResponseWriter, r *http.Request) string {
	const cookieName = "sid"

	if c, err := r.Cookie(cookieName); err == nil && c.Value != "" {
		return c.Value
	}

	sid := newRandomHex(16)
	http.SetCookie(w, &http.Cookie{
		Name:     cookieName,
		Value:    sid,
		Path:     "/",
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
		Expires:  time.Now().Add(365 * 24 * time.Hour),
	})
	return sid
}

func newRandomHex(nBytes int) string {
	b := make([]byte, nBytes)
	if _, err := rand.Read(b); err != nil {
		// Fallback: time-based if crypto/rand fails (still standard library).
		now := time.Now().UnixNano()
		return hex.EncodeToString([]byte(string(rune(now))))
	}
	return hex.EncodeToString(b)
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For first (common in proxies); take first value.
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			ip := strings.TrimSpace(parts[0])
			if ip != "" {
				return ip
			}
		}
	}
	if xrip := strings.TrimSpace(r.Header.Get("X-Real-IP")); xrip != "" {
		return xrip
	}
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err == nil && host != "" {
		return host
	}
	return r.RemoteAddr
}

func logAnalytics(ev analyticsEvent) {
	// Simple analytics support: emit JSON to server logs.
	b, err := json.Marshal(ev)
	if err != nil {
		log.Printf("analytics_error: %v", err)
		return
	}
	log.Printf("analytics: %s", b)
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/search", HandleProductSearch)

	srv := &http.Server{
		Addr:              ":8080",
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
	}

	log.Printf("listening on http://localhost%s/search?keyword=shoes", srv.Addr)
	log.Fatal(srv.ListenAndServe())
}

