	"net"
	"net/http"
	"strings"
	"time"
)

type AnalyticsEvent struct {
	Event     string    `json:"event"`
	Keyword   string    `json:"keyword"`
	Path      string    `json:"path"`
	Referer   string    `json:"referer,omitempty"`
	UserAgent string    `json:"user_agent,omitempty"`
	IP        string    `json:"ip,omitempty"`
	Time      time.Time `json:"time"`
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For (first IP), then X-Real-IP, then RemoteAddr.
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			ip := strings.TrimSpace(parts[0])
			if ip != "" {
				return ip
			}
		}
	}
	if xrip := strings.TrimSpace(r.Header.Get("X-Real-IP")); xrip != "" {
		return xrip
	}
	host, _, err := net.SplitHostPort(strings.TrimSpace(r.RemoteAddr))
	if err == nil && host != "" {
		return host
	}
	return strings.TrimSpace(r.RemoteAddr)
}

func logSearchAnalytics(r *http.Request, keyword string) {
	ev := AnalyticsEvent{
		Event:     "product_search",
		Keyword:   keyword,
		Path:      r.URL.Path,
		Referer:   r.Referer(),
		UserAgent: r.UserAgent(),
		IP:        clientIP(r),
		Time:      time.Now().UTC(),
	}
	b, err := json.Marshal(ev)
	if err != nil {
		log.Printf("analytics marshal error: %v", err)
		return
	}
	log.Printf("analytics %s", string(b))
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")
	logSearchAnalytics(r, keyword)

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escaped := html.EscapeString(keyword)

	// Minimal HTML page with required title area.
	_, _ = w.Write([]byte(`<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Search Results</title>
</head>
<body>
  <main>
    <h2>Search Results: ` + escaped + `</h2>
  </main>
</body>
</html>`))
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/search", HandleProductSearch)

	srv := &http.Server{
		Addr:              ":8080",
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
	}

	log.Printf("listening on http://localhost%s/search?keyword=shoes", srv.Addr)
	if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatal(err)
	}
}

