		}
	}
	if xrip := strings.TrimSpace(r.Header.Get("X-Real-IP")); xrip != "" {
		return xrip
	}
	host := r.RemoteAddr
	// r.RemoteAddr is usually "IP:port"; keep as-is if parsing isn't necessary.
