func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	// Analytics: emit a lightweight JSON event to server logs.
	event := map[string]any{
		"event":      "product_search",
		"keyword":    keyword,
		"path":       r.URL.Path,
		"method":     r.Method,
		"remoteAddr": r.RemoteAddr,
		"userAgent":  r.UserAgent(),
		"ts":         time.Now().UTC().Format(time.RFC3339Nano),
	}
	if b, err := json.Marshal(event); err == nil {
		log.Print(string(b))
	}

	// Write HTML response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escaped := html.EscapeString(keyword)

	_, _ = w.Write([]byte("<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<title>Search Results</title>\n</head>\n<body>\n"))
	_, _ = w.Write([]byte("<h2>Search Results: [" + escaped + "]</h2>\n"))
	_, _ = w.Write([]byte("</body>\n</html>\n"))
}

func main() {
	mux := http.NewServeMux()

	mux.HandleFunc("/search", HandleProductSearch)

	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "text/html; charset=utf-8")
		_, _ = w.Write([]byte("<!doctype html><html><body><p>Try <a href=\"/search?keyword=shoes\">/search?keyword=shoes</a></p></body></html>"))
	})

	_ = http.ListenAndServe(":8080", mux)
}

