	"html"
	"net/http"
	"time"
)

type analyticsEvent struct {
	Event     string    `json:"event"`
	Keyword   string    `json:"keyword"`
	Path      string    `json:"path"`
	UserAgent string    `json:"user_agent"`
	RemoteIP  string    `json:"remote_ip"`
	Time      time.Time `json:"time"`
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For if present (common behind proxies).
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		return xff
	}
	if xrip := r.Header.Get("X-Real-IP"); xrip != "" {
		return xrip
	}
	return r.RemoteAddr
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	// Basic analytics support: emit a JSON event to a response header.
	// (In real deployments this would be sent to a logging/analytics sink.)
	ev := analyticsEvent{
		Event:     "product_search",
		Keyword:   keyword,
		Path:      r.URL.Path,
		UserAgent: r.UserAgent(),
		RemoteIP:  clientIP(r),
		Time:      time.Now().UTC(),
	}
	if b, err := json.Marshal(ev); err == nil {
		// Keep it small; if too large, omit.
		if len(b) <= 1024 {
			w.Header().Set("X-Analytics-Event", string(b))
		}
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escapedKeyword := html.EscapeString(keyword)

	// Minimal HTML page with required title area.
	_, _ = w.Write([]byte(`<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Search Results</title>
</head>
<body>
  <main>
    <h2>Search Results: [` + escapedKeyword + `]</h2>
  </main>
</body>
</html>`))
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/search", HandleProductSearch)

	srv := &http.Server{
		Addr:              ":8080",
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
	}

	_ = srv.ListenAndServe()
}

