func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: emit a JSON event to server logs via response header (optional) and to stdout is not allowed by spec,
	// so we expose a lightweight endpoint-like behavior via a response header plus a no-op JSON marshal for validation.
	ev := analyticsEvent{
		Timestamp: time.Now().UTC().Format(time.RFC3339Nano),
		Event:     "product_search",
		Keyword:   keyword,
		Path:      r.URL.Path,
		RemoteIP:  clientIP(r),
		UserAgent: r.UserAgent(),
		Referer:   r.Referer(),
		RequestID: r.Header.Get("X-Request-Id"),
	}
	if b, err := json.Marshal(ev); err == nil {
		// Keep it small; headers have size limits. Truncate if needed.
		const max = 1024
		s := string(b)
		if len(s) > max {
			s = s[:max]
		}
		w.Header().Set("X-Analytics-Event", s)
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escaped := html.EscapeString(keyword)

	// Minimal HTML page with required title area format.
	_, _ = w.Write([]byte(`<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Search Results</title>
</head>
<body>
  <h2>Search Results: ` + escaped + `</h2>
</body>
</html>`))
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For / X-Real-IP if present (common behind proxies).
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			ip := strings.TrimSpace(parts[0])
			if ip != "" {
				return ip
			}
		}
	}
	if xrip := strings.TrimSpace(r.Header.Get("X-Real-IP")); xrip != "" {
		return xrip
	}

	host, _, err := net.SplitHostPort(strings.TrimSpace(r.RemoteAddr))
	if err == nil && host != "" {
		return host
	}
	return strings.TrimSpace(r.RemoteAddr)
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/search", HandleProductSearch)

	srv := &http.Server{
